SELECT id, tag_id, tenant_id, name, created_at, updated_at, deleted
FROM kb_tag
WHERE tenant_id = #{tenantId}
  AND name = #{name}
  AND deleted = FALSE
LIMIT 1

SELECT id, category_id, tenant_id, scope, owner_user_id, parent_id, name, sort_order, created_at, updated_at, deleted
FROM kb_category
WHERE tenant_id = #{tenantId}
  AND scope = #{scope}
  AND deleted = FALSE

  AND owner_user_id = #{ownerUserId}


  AND owner_user_id IS NULL

ORDER BY sort_order ASC, created_at ASC

mapper.update:
UPDATE kb_category
SET parent_id = #{parentId},
    name = #{name},
    sort_order = #{sortOrder},
    updated_at = CURRENT_TIMESTAMP
WHERE category_id = #{categoryId}
  AND scope = #{scope}
  AND deleted = FALSE

  AND owner_user_id = #{ownerUserId}

UPDATE kb_category
SET deleted = TRUE,
    updated_at = CURRENT_TIMESTAMP
WHERE category_id = #{categoryId}
  AND tenant_id = #{tenantId}
  AND scope = #{scope}
  AND deleted = FALSE

  AND owner_user_id = #{ownerUserId}


  AND owner_user_id IS NULL

